text:
{
  "formal_minutes": {
    "회의메타": {
      "project_code": "PUBLIC_MEETING_SMOKE",
      "meeting_title": "UI Theme Package Release Readiness",
      "participants": ["Minjun", "Seoyeon", "Doyun", "Hara"]
    },
    "확정_결정": [
      {
        "항목": "대외 공개 릴리스 목표 시각",
        "내용": "스모크 테스트 통과 시 금요일 15:00 KST에 공개 릴리스를 목표로 한다.",
        "조건": "스모크 테스트 통과"
      },
      {
        "항목": "packageName 불일치 대응 원칙",
        "내용": "packageName mismatch 발생 시 먼저 패키지 설정(config)을 점검하고, 계약(contract) 자체가 잘못된 경우에만 스크립트 검토로 진행한다."
      }
    ],
    "반려_제안": [
      {
        "제안자": "Hara",
        "제안": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경",
        "결론": "반려"
      }
    ],
    "내부_스트레치_목표": [
      {
        "항목": "수요일 릴리스 제안",
        "상태": "내부 스트레치 목표(확정 일정 아님)",
        "비고": "Doyun 이의 제기로 확정되지 않음"
      }
    ],
    "비결정_및_보류": [
      {
        "항목": "README 설치 절차 검토",
        "내용": "목요일까지 가능하면 검토 필요 의견이 있었으나 담당자 미지정"
      },
      {
        "항목": "Hara의 tarball 경로 확인",
        "내용": "Minjun의 스모크 결과 공유 이후 점검하기로 했으나 정확한 기한 미설정"
      }
    ],
    "리스크": [
      {
        "항목": "tarball 경로 오류",
        "영향": "릴리스 지연 가능"
      },
      {
        "항목": "README 설치 절차 노후화",
        "영향": "릴리스 노트가 사용자에게 오해를 줄 수 있음"
      }
    ],
    "오픈_질문": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트 재실행 후 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "예정",
      "source_certainty": "확정"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트를 action_items.md에 작성",
      "due": "금요일 12:00 KST",
      "status": "예정",
      "source_certainty": "확정"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 이후 생성된 tarball 경로 점검",
      "due": "미정",
      "status": "선행조건 대기",
      "source_certainty": "확정(기한 미확정)"
    },
    {
      "owner": "미지정",
      "task": "README 설치 절차 검토(가능하면 목요일)",
      "due": "목요일(가능 시)",
      "status": "담당자 미배정",
      "source_certainty": "부분확정(요청 존재, 담당 미정)"
    }
  ],
  "followup_note": {
    "다음_확인사항": [
      "금요일 10:00 KST 기준 Minjun 스모크 테스트 결과 수신 여부",
      "금요일 12:00 KST 기준 Doyun triage note(action_items.md) 작성 여부",
      "스모크 결과 공유 직후 Hara의 tarball 경로 검증 결과",
      "README 설치 절차 검토 담당자 지정 여부",
      "최종 릴리스 승인 권한자 확정",
      "릴리스 노트에 수요일 내부 스트레치 목표 언급 여부 결정"
    ],
    "주의사항": [
      "수요일 릴리스는 확정 일정이 아니라 내부 스트레치 목표로만 기록",
      "반려된 제안(packageName mismatch 무시)은 실행 항목으로 전환하지 않음"
    ]
  },
  "non_invention_rules": [
    "고객명 또는 외부 파트너를 추가로 만들지 않는다.",
    "예산 정보(금액, 승인, 집행)를 만들지 않는다.",
    "보안 사고를 언급하거나 추정하지 않는다.",
    "프로덕션 장애/다운타임 사실을 만들지 않는다.",
    "법무 승인 요구사항을 만들지 않는다.",
    "명시되지 않은 owner 또는 deadline을 임의 확정하지 않는다."
  ]
}
